// With newline
System.out.println("Hello");
System.out.println("World");
// Output: Hello
//       World

// Without newline
System.out.print("Hello");
System.out.print("World");
// Output: HelloWorld

// Format specification
System.out.printf("Name is %s. Age is %d years old.", "Taro", 20);
// Output: Name is Taro. Age is 20 years old.

// \n → Newline
System.out.println("Hello\nWorld");
// Output: Hello
//       World

// \t → Tab (indent)
System.out.println("Name\tAge");
System.out.println("Taro\t20");
// Output: Name	Age
//       Taro	20

// \\ → Backslash itself
System.out.println("C:\\Users\\");
// Output: C:\Users\

// \" → Double quote
System.out.println("He \"Java\"likes");
// Output: He "Java"likes

int price = 1980;
double tax = 1.10;
System.out.printf("ProductPrice: %d yen%n", price);
System.out.printf("Price including tax: %.0f yen%n", price * tax);
// Output: ProductPrice: 1980 yen
//       Price including tax: 2178 yen

// Declaration and assignment separately
int age;        // Declaration(Create an int variable 'age')
age = 25;       // Assignment(Assign 25 to age)

// Initialization(Declaration and assignment at the same time)
String name = "Taro";
double height = 170.5;

// Display the variable value
System.out.println(name);   // Taro
System.out.println(age);    // 25

// Variable declaration and initialization
int a = 10;
int b = 3;

System.out.println(a + b);  // 13(Addition)
System.out.println(a - b);  // 7 (Subtraction)
System.out.println(a * b);  // 30(Multiplication)
System.out.println(a / b);  // 3 (Integer division truncates decimals)
System.out.println(a % b);  // 1 (Remainder)

