// Variable declaration and initialization
String first = "Hello";
String second = "World";
String greeting = first + " " + second;
System.out.println(greeting);  // Hello World

// Number and String concatenation
int age = 20;
System.out.println("Age is " + age + " years old");  // Age is 20 years old

// Variable declaration and initialization
String s = "Hello, Java!";

s.length()          // 12(Character count)
s.charAt(0)         // 'H'(0th character)
s.contains("Java")  // true(Check if it contains)
s.toUpperCase()     // "HELLO, JAVA!"
s.toLowerCase()     // "hello, java!"
s.replace("Java", "World")  // "Hello, World!"

// Use equals() for String comparison
String a = "abc";
String b = "abc";
a.equals(b)  // true ✓
// a == b Don't use as it compares references ✗

String s = "Hello, Java!";

// indexOf: Search for position in String(returns -1 if not found)
s.indexOf("Java")     // 7
s.indexOf("Python")   // -1

// substring: Extract part of a String
s.substring(7)        // "Java!"(From index 7 onwards)
s.substring(0, 5)     // "Hello"(0~4th)

// trim: Remove surrounding whitespace
"  Hello  ".trim()    // "Hello"

// startsWith / endsWith: Beginning/End check
s.startsWith("Hello") // true
s.endsWith("!")       // true

// isEmpty / isBlank(Java 11+)
"".isEmpty()           // true
"  ".isEmpty()         // false
"  ".isBlank()         // true(Whitespace only)

int i = 100;
double d = i;  // int → double Automatic conversion OK
System.out.println(d);  // 100.0

// From smaller to larger type
// byte → short → int → long → float → double

double d = 3.14;
int i = (int) d;  // Cast: double → int
System.out.println(i);  // 3(Decimal part is truncated)

// String to Number conversion
String numStr = "123";
int num = Integer.parseInt(numStr);  // 123
double dbl = Double.parseDouble("3.14"); // 3.14

// Number to String conversion
String s = String.valueOf(100);  // "100"

